import { Navigate, useLocation } from "react-router-dom";

export default function ProtectedRoute({ children, allowedRoles = [] }) {
  // Check authentication status synchronously from localStorage
  const token = localStorage.getItem("access_token");
  const userRole = localStorage.getItem("role");
  const location = useLocation();

  // Not authenticated - redirect to appropriate login
  if (!token) {
    // If trying to access customer routes, redirect to customer login
    if (allowedRoles.includes("customer") || location.pathname === "/profile") {
      return <Navigate to="/login" state={{ from: location }} replace />;
    }
    return <Navigate to="/staff-login" state={{ from: location }} replace />;
  }

  // If no role is set but token exists, treat as not authenticated
  if (!userRole) {
    // Clear invalid session
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('username');
    localStorage.removeItem('email');
    localStorage.removeItem('role');
    localStorage.removeItem('admin_id');
    localStorage.removeItem('staff_id');
    localStorage.removeItem('customer_id');
    
    if (allowedRoles.includes("customer") || location.pathname === "/profile") {
      return <Navigate to="/login" state={{ from: location }} replace />;
    }
    return <Navigate to="/staff-login" state={{ from: location }} replace />;
  }

  // Check role authorization - if user has a role but it's not in allowedRoles
  if (allowedRoles.length > 0 && !allowedRoles.includes(userRole)) {
    // User doesn't have required role - redirect to their appropriate dashboard
    if (userRole === "admin") {
      return <Navigate to="/admin" replace />;
    } else if (userRole === "staff") {
      return <Navigate to="/staff" replace />;
    } else if (userRole === "customer") {
      // Customer trying to access admin/staff routes - redirect to home
      return <Navigate to="/" replace />;
    } else {
      // No valid role - clear all session data and redirect to login
      localStorage.removeItem('access_token');
      localStorage.removeItem('refresh_token');
      localStorage.removeItem('username');
      localStorage.removeItem('email');
      localStorage.removeItem('role');
      localStorage.removeItem('admin_id');
      localStorage.removeItem('staff_id');
      localStorage.removeItem('customer_id');
      return <Navigate to="/login" replace />;
    }
  }

  return children;
}
